SELECT AVG(modal_price), AVG(quantity_sold)
FROM price_data
WHERE market_id = 1;

SELECT AVG(modal_price) AS average_modal_price
FROM price_data
WHERE commodity_id = 0 AND verified = 1;

SELECT DISTINCT grade_id
FROM price_data
WHERE commodity_id = 1;

SELECT commodity_name 
FROM commodities 
WHERE commodity_id = 0;

SELECT market_name 
FROM markets 
WHERE market_id = 1;

SELECT district_name, population 
FROM districts 
ORDER BY population DESC;

SELECT DISTINCT v.variety_id, v.commodity_id, v.variety_name, v.yield, v.disease_resistance
FROM varieties AS v
INNER JOIN price_data AS pd ON v.variety_id = pd.variety_id;
